 #include <bits/stdc++.h>
using namespace std;
const int N=100005,M=30005;
int n,m,u[N],v[N],ru[N],a[N];
vector<int> g[M],g2[M];
bitset<M> bs1[M],bs2[M];
void topo()
{
	queue<int> q;
	int cnt=0;
	for(int i=1;i<=n;i++)
	{
		if(ru[i]==0) q.push(i);
	}
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		a[++cnt]=u;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i];
			ru[v]--;
			if(ru[v]==0) q.push(v);
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>u[i]>>v[i];
		g[u[i]].push_back(v[i]);
		g2[v[i]].push_back(u[i]);
		ru[v[i]]++;
	}
	topo();
	for(int i=n;i>0;i--)
	{
		int u=a[i];
		for(int j=0;j<g[u].size();j++)
		{
			int v=g[u][j];
            bs1[u][v]=1;
			bs1[u]|=bs1[v];
		}
	}
	for(int i=1;i<=n;i++)
	{
		int u=a[i];
		for(int j=0;j<g2[u].size();j++)
		{
			int v=g2[u][j];
            bs2[u][v]=1;
			bs2[u]|=bs2[v];
		}
	}
	int ans=0;
	for(int i=1;i<=m;i++)
	{
		if((bs1[u[i]]&bs2[v[i]])!=0) ans++;
	}
	cout<<ans;
	return 0;
}
